// Tier represents the analysis capability level for a language.
type Tier int

const (
	TierNone    Tier = iota // 0 – no analysis possible
	TierGeneric             // 1 – generic/file-level only
	TierLint                // 2 – lint-capable
	TierParse               // 3 – parse/ast-capable
	TierFull                // 4 – full semantic analysis
)

var tierNames = map[Tier]string{
	TierNone:    "None",
	TierGeneric: "Generic",
	TierLint:    "Lint",
	TierParse:   "Parse",
	TierFull:    "Full",
}

// String returns the human-readable name of the tier.
func (t Tier) String() string {
	if name, ok := tierNames[t]; ok {
		return name
	}
	return "Unknown"
}

// languageTiers maps every known language ID to its analysis capability tier.
var languageTiers = map[string]Tier{
	// TierFull languages (deep semantic analysis)
	"go": TierFull,
	"ts": TierFull,
	"js": TierFull,
	"py": TierFull,
	"rs": TierFull,

	// TierGeneric languages (file-level classification only)
	"rb":     TierGeneric,
	"java":   TierGeneric,
	"kt":     TierGeneric,
	"sh":     TierGeneric,
	"c":      TierGeneric,
	"cpp":    TierGeneric,
	"cs":     TierGeneric,
	"swift":  TierGeneric,
	"php":    TierGeneric,
	"elixir": TierGeneric,
	"erlang": TierGeneric,
	"scala":  TierGeneric,
	"lua":    TierGeneric,
	"r":      TierGeneric,
	"zig":    TierGeneric,
	"sql":    TierGeneric,
	"proto":  TierGeneric,
}

// TierForLanguage returns the analysis tier for the given language ID.
// Unknown languages return TierGeneric.
func TierForLanguage(lang string) Tier {
	if tier, ok := languageTiers[lang]; ok {
		return tier
	}
	return TierGeneric
}

